You can use this cloud function to manage accounts and transactions. Here's sample code for testing the cloud function call in the mini-program:

```js
// Create
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'createAccount',
    data: {
      name: 'David',
      initialBalance: 1000
    }
  }
}).then(res => {
  console.log('Create: ', res)
})

// response
{
  "id": "xxx",
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1"
}

// Transfer
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'transfer',
    data: {
      fromAccountId: 'account1',
      toAccountId: 'account2',
      amount: 100
    }
  }
}).then(res => {
  console.log('Transfer: ', res)
})

// response
{
  "success": true,
  "recordId": "xxx"
}

// Batch Transfer
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'batchTransfer',
    data: {
      fromAccountId: 'account1',
      transfers: [
        { toAccountId: 'account2', amount: 50 },
        { toAccountId: 'account3', amount: 50 }
      ]
    }
  }
}).then(res => {
  console.log('Batch Transfer: ', res)
})

// response
{
  "success": true,
  "records": ["xxx1", "xxx2"]
}

// Check balance
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'getBalance',
    data: {
      accountId: 'account1'
    }
  }
}).then(res => {
  console.log('Check balance: ', res)
})

// response
{
    "result": 800
}


// Check transaction history
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'getTransactionHistory',
    data: {
      accountId: 'account1'
    }
  }
}).then(res => {
  console.log('Check transaction history: ', res)
})

// response
{
  "data": [
    {
      "_id": "record3",
      "fromAccount": "account1",
      "toAccount": "account3",
      "amount": 50,
      "status": "success",
      "createdAt": "2023-08-02T08:30:15.000Z",
      "updatedAt": "2023-08-02T08:30:15.000Z"
    },
    {
      "_id": "record2",
      "fromAccount": "account1",
      "toAccount": "account2",
      "amount": 50,
      "status": "success",
      "createdAt": "2023-08-02T08:30:15.000Z",
      "updatedAt": "2023-08-02T08:30:15.000Z"
    },
    {
      "_id": "record1",
      "fromAccount": "account1",
      "toAccount": "account2",
      "amount": 100,
      "status": "success",
      "createdAt": "2023-08-02T08:30:15.000Z",
      "updatedAt": "2023-08-02T08:30:15.000Z"
    }
  ],
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1"
}

```
